#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2000005;
ll n,cnt[N],num[N],ans;
string s;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>s;
	s=" "+s;
	for(int i=1;i<=n;i++)
	{
		int tmp=i-1;
		while(tmp>0)
		{
			if(s[tmp]==s[i]) break;
			tmp=num[tmp]-1;
		}
		if(tmp<=0) num[i]=0;
		else
		{
			num[i]=tmp;
			cnt[i]=cnt[tmp-1]+1;
			ans+=cnt[i];
		}
	}
	cout<<ans;
	return 0;
}
